#include<bits/stdc++.h>
#define ll long long
#define CI const int
using namespace std;
CI MAXN=2e3+5;
ll id[MAXN],ans=0;int f[MAXN],n;
struct Node{int i,j;ll v;}a[MAXN*MAXN];
int find(int x){return ((f[x]==x)?(x):(f[x]=find(f[x])));}
bool cmp(Node a,Node b){return a.v>b.v;}
int main(void){
	scanf("%d",&n);
	for(int i=1;i<=n;++i)scanf("%lld",&id[i]),f[i]=i;
	int size=0;
	for(int i=1;i<n;++i)
		for(int j=i+1;j<=n;++j)
		a[++size].i=i,a[size].j=j,a[size].v=id[i]^id[j];
	sort(a+1,a+size+1,cmp);
	for(int i=1;i<size;++i){
		int fx=find(a[i].i),fy=find(a[i].j);
		if(fx!=fy)f[fx]=fy,--n,ans+=a[i].v;
		if(n==1){printf("%lld",ans);return false;}
	}return false;
}
